import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';
import CssBaseline from '@material-ui/core/CssBaseline';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <CssBaseline />
    <App />
  </React.StrictMode>
);
